    <script>
        fetch('api/get-borrowed-books.php').then(r=>r.json()).then(data=>{const list=document.getElementById('bookList');if(data.success&&data.books.length>0){let html='';data.books.forEach(book=>{const isOverdue=book.status==='Overdue';html+=`<div class="book-item"><div><div class="book-title">${book.title}</div><div class="due-date">by ${book.author}</div></div><div><div class="due-date">Borrowed: ${book.borrow_date}</div><div class="due-date ${isOverdue?'overdue':''}">Due: ${book.due_date}</div>${isOverdue?`<div class="overdue">⚠️ Overdue by ${book.days_overdue} days</div>`:''}${book.fine_amount>0?`<div class="overdue">Fine: $${parseFloat(book.fine_amount).toFixed(2)}</div>`:''}</div></div>`;});list.innerHTML=html;}else{list.innerHTML='<p style="text-align:center; padding:20px;">📭 You have no borrowed books.</p>';}}).catch(error=>{document.getElementById('bookList').innerHTML='<p style="text-align:center; padding:20px;">❌ Error loading borrowed books.</p>';});
